package com.optiplant.backend.configuration;

import org.springframework.context.annotation.Configuration;
import org.springframework.messaging.simp.config.MessageBrokerRegistry;
import org.springframework.web.socket.config.annotation.EnableWebSocketMessageBroker;
import org.springframework.web.socket.config.annotation.StompEndpointRegistry;
import org.springframework.web.socket.config.annotation.WebSocketMessageBrokerConfigurer;

@Configuration
@EnableWebSocketMessageBroker
public class WebSocketConfig implements WebSocketMessageBrokerConfigurer {

    @Override
    public void configureMessageBroker(MessageBrokerRegistry registry) {
        registry.enableSimpleBroker("/topic");
        registry.setApplicationDestinationPrefixes("/app");
    }

    @Override
    public void registerStompEndpoints(StompEndpointRegistry registry) {
        // Endpoint WebSocket nativo (sin SockJS)
        registry.addEndpoint("/ws")
                .setAllowedOriginPatterns("*");

        // Endpoint con SockJS como fallback (por si acaso)
        registry.addEndpoint("/ws")
                .setAllowedOriginPatterns("*")
                .withSockJS();
    }
}

package com.optiplant.backend.configuration;

import org.springframework.context.annotation.Configuration;
import org.springframework.messaging.simp.config.MessageBrokerRegistry;
import org.springframework.messaging.simp.config.ChannelRegistration;
import org.springframework.web.socket.config.annotation.EnableWebSocketMessageBroker;
import org.springframework.web.socket.config.annotation.WebSocketMessageBrokerConfigurer;
import org.springframework.web.socket.config.annotation.StompEndpointRegistry;

import com.optiplant.backend.configuration.security.StompAuthChannelInterceptor;

@Configuration
@EnableWebSocketMessageBroker
public class WebSocketConfig implements WebSocketMessageBrokerConfigurer {

    private final StompAuthChannelInterceptor stompAuthChannelInterceptor;

    public WebSocketConfig(StompAuthChannelInterceptor stompAuthChannelInterceptor) {
        this.stompAuthChannelInterceptor = stompAuthChannelInterceptor;
    }

    @Override
    public void configureMessageBroker(MessageBrokerRegistry registry) {
        registry.enableSimpleBroker("/topic", "/queue");
        registry.setApplicationDestinationPrefixes("/app");
        registry.setUserDestinationPrefix("/user");
    }

    @Override
    public void configureClientInboundChannel(ChannelRegistration registration) {
        registration.interceptors(stompAuthChannelInterceptor);
    }

    @Override
    public void registerStompEndpoints(StompEndpointRegistry registry) {
        // Endpoint WebSocket nativo (sin SockJS)
        registry.addEndpoint("/ws")
                .setAllowedOriginPatterns("*");

        // Endpoint con SockJS como fallback (por si acaso)
        registry.addEndpoint("/ws")
                .setAllowedOriginPatterns("*")
                .withSockJS();
    }
}

package com.optiplant.backend.configuration.security;

import java.security.Principal;
import java.util.Collection;

import org.springframework.messaging.Message;
import org.springframework.messaging.MessageChannel;
import org.springframework.messaging.simp.stomp.StompCommand;
import org.springframework.messaging.simp.stomp.StompHeaderAccessor;
import org.springframework.messaging.support.ChannelInterceptor;
import org.springframework.messaging.support.MessageHeaderAccessor;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.stereotype.Component;

import io.jsonwebtoken.Claims;

@Component
public class StompAuthChannelInterceptor implements ChannelInterceptor {

    private final JwtService jwtService;
    private final JwtRoleConverter jwtRoleConverter;

    public StompAuthChannelInterceptor(JwtService jwtService, JwtRoleConverter jwtRoleConverter) {
        this.jwtService = jwtService;
        this.jwtRoleConverter = jwtRoleConverter;
    }

    @Override
    public Message<?> preSend(Message<?> message, MessageChannel channel) {
        StompHeaderAccessor accessor = MessageHeaderAccessor.getAccessor(message, StompHeaderAccessor.class);
        if (accessor == null) {
            return message;
        }

        if (StompCommand.CONNECT.equals(accessor.getCommand())) {
            String authHeader = accessor.getFirstNativeHeader("Authorization");
            if (authHeader == null || authHeader.isBlank()) {
                throw new RuntimeException("Authorization header is required for WebSocket CONNECT");
            }

            String token = authHeader.startsWith("Bearer ") ? authHeader.substring(7) : authHeader;
            if (!jwtService.isTokenValid(token)) {
                throw new RuntimeException("Invalid JWT token");
            }

            Claims claims = jwtService.extractClaims(token);
            String username = claims.getSubject();
            Collection<? extends GrantedAuthority> authorities = jwtRoleConverter.convert(claims);

            if (username == null || username.isBlank() || authorities == null || authorities.isEmpty()) {
                throw new RuntimeException("Invalid authentication data in JWT token");
            }

            Principal principal = new UsernamePasswordAuthenticationToken(username, null, authorities);
            accessor.setUser(principal);
        }

        return message;
    }
}

package com.optiplant.backend.controller;

import java.security.Principal;
import java.util.List;

import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.validation.annotation.Validated;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import com.optiplant.backend.dto.ChatConversationResponse;
import com.optiplant.backend.dto.ChatMessageResponse;
import com.optiplant.backend.dto.CreateAdminConversationRequest;
import com.optiplant.backend.dto.CreateBranchConversationRequest;
import com.optiplant.backend.dto.CreateChatMessageRequest;
import com.optiplant.backend.service.ChatService;

import jakarta.validation.Valid;

@RestController
@RequestMapping("/chat")
@Validated
public class ChatController {

    private final ChatService chatService;

    public ChatController(ChatService chatService) {
        this.chatService = chatService;
    }

    @PostMapping("/conversations/admin-branch")
    @PreAuthorize("hasRole('ADMIN')")
    public ChatConversationResponse createAdminBranchConversation(@Valid @RequestBody CreateAdminConversationRequest request,
                                                                  Principal principal) {
        return chatService.createAdminConversation(principal.getName(), request.branchId());
    }

    @PostMapping("/conversations/branch-branch")
    @PreAuthorize("hasRole('ADMIN') or hasRole('SUCURSAL')")
    public ChatConversationResponse createBranchConversation(@Valid @RequestBody CreateBranchConversationRequest request,
                                                             Principal principal) {
        return chatService.createBranchConversation(
                principal.getName(),
                request.sourceBranchId(),
                request.destinationBranchId()
        );
    }

    @GetMapping("/conversations")
    @PreAuthorize("hasRole('ADMIN') or hasRole('SUCURSAL')")
    public List<ChatConversationResponse> getMyConversations(Principal principal) {
        return chatService.getMyConversations(principal.getName());
    }

    @GetMapping("/conversations/{conversationId}/messages")
    @PreAuthorize("hasRole('ADMIN') or hasRole('SUCURSAL')")
    public List<ChatMessageResponse> getMessages(@PathVariable Long conversationId,
                                                 @RequestParam(required = false) Integer page,
                                                 @RequestParam(required = false) Integer size,
                                                 Principal principal) {
        return chatService.getConversationMessages(principal.getName(), conversationId, page, size);
    }

    @PostMapping("/messages")
    @PreAuthorize("hasRole('ADMIN') or hasRole('SUCURSAL')")
    public ChatMessageResponse sendMessage(@Valid @RequestBody CreateChatMessageRequest request,
                                           Principal principal) {
        return chatService.sendMessage(principal.getName(), request);
    }
}

package com.optiplant.backend.controller;

import java.security.Principal;

import org.springframework.messaging.handler.annotation.MessageMapping;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.validation.annotation.Validated;
import org.springframework.web.bind.annotation.RestController;

import com.optiplant.backend.dto.ChatMessageResponse;
import com.optiplant.backend.dto.CreateChatMessageRequest;
import com.optiplant.backend.service.ChatService;

import jakarta.validation.Valid;

@RestController
@Validated
public class ChatWebSocketController {

    private final ChatService chatService;

    public ChatWebSocketController(ChatService chatService) {
        this.chatService = chatService;
    }

    @MessageMapping("/chat.send")
    @PreAuthorize("hasRole('ADMIN') or hasRole('SUCURSAL')")
    public ChatMessageResponse sendMessage(@Valid CreateChatMessageRequest request, Principal principal) {
        if (principal == null || principal.getName() == null || principal.getName().isBlank()) {
            throw new RuntimeException("Sesion WebSocket no autenticada");
        }
        return chatService.sendMessage(principal.getName(), request);
    }
}

package com.optiplant.backend.dto;

import java.time.LocalDateTime;

public record ChatMessageResponse(
        Long id,
        Long conversationId,
        Long senderId,
        String senderUsername,
        Long senderBranchId,
        String senderBranchName,
        String content,
        LocalDateTime createdAt
) {
}

package com.optiplant.backend.repository;

import java.util.Optional;

import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;

import com.optiplant.backend.entity.ChatMessage;

public interface ChatMessageRepository extends JpaRepository<ChatMessage, Long> {

    Page<ChatMessage> findByConversationIdOrderByCreatedAtDesc(Long conversationId, Pageable pageable);

    Optional<ChatMessage> findTopByConversationIdOrderByCreatedAtDesc(Long conversationId);
}

package com.optiplant.backend.repository;

import java.util.Optional;

import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;

import com.optiplant.backend.entity.ChatMessage;

public interface ChatMessageRepository extends JpaRepository<ChatMessage, Long> {

    Page<ChatMessage> findByConversationIdOrderByCreatedAtDesc(Long conversationId, Pageable pageable);

    Page<ChatMessage> findByConversationIdOrderByCreatedAtAsc(Long conversationId, Pageable pageable);

    Optional<ChatMessage> findTopByConversationIdOrderByCreatedAtDesc(Long conversationId);
}
